// Pull the fields we need from the Notion trigger payload.
// Notion returns properties as structured objects — we unpack them here
// so downstream nodes can use simple $json.* references.
const p = $input.first().json.properties ?? {};

function text(prop)  { return prop?.rich_text?.[0]?.plain_text ?? prop?.title?.[0]?.plain_text ?? ''; }
function select(prop){ return prop?.select?.name ?? ''; }
function email(prop) { return prop?.email ?? ''; }
function url(prop)   { return prop?.url ?? ''; }
function multi(prop) { return (prop?.multi_select ?? []).map(s => s.name); }
function date(prop)  { return prop?.date?.start ?? ''; }

// ── property names below must match your Clients DB exactly ───────────
// These match the property keys written by the intake workflow.
const client = {
  page_id:       $input.first().json.id,
  page_url:      $input.first().json.url,
  company_name:  text(p['Name'] ?? p['Company']),          // Notion title prop (may be 'Name' or 'Company')
  contact_name:  text(p['Contact Name']),
  contact_email: email(p['Contact Email']),
  team_size:     select(p['Team Size']),
  pain_primary:  select(p['Pain Point']),
  cloud:         select(p['Cloud']),
  compliance:    select(p['Compliance']),
  automation:    text(p['Automation']),
  tools_crm:     text(p['Tools — CRM']),
  tools_pm:      text(p['Tools — PM']),
  tools_comms:   text(p['Tools — Comms']),
  off_limits:    text(p['Off-limits']),
  tags:          multi(p['Tags']),
  submitted_at:  date(p['Submitted At']),
};

// Blueprint page title convention
client.blueprint_title = `Blueprint — ${client.company_name}`;

return [{ json: client }];
